import { useEffect, useRef, useState } from 'react';
import { createChart, BaselineSeries } from 'lightweight-charts';

function BaselineChart({sparklinedata}) {
  let [newarr, changenewarr] = useState([])
  const chartContainerRef = useRef(null);
  console.log(sparklinedata)
  useEffect(() => {
    const chart = createChart(chartContainerRef.current, {
      layout: {
        textColor: 'black',
        background: {
          type: 'solid',
          color: 'white',
        },
      },
      width: 900,
      height: 400,
    });

    const baselineSeries = chart.addSeries(BaselineSeries, {
      baseValue: {
        type: 'price',
        price: 25,
      },
      topLineColor: 'rgba(38, 166, 154, 1)',
      topFillColor1: 'rgba(38, 166, 154, 0.28)',
      topFillColor2: 'rgba(38, 166, 154, 0.05)',
      bottomLineColor: 'rgba(239, 83, 80, 1)',
      bottomFillColor1: 'rgba(239, 83, 80, 0.05)',
      bottomFillColor2: 'rgba(239, 83, 80, 0.28)',
    });
    sparklinedata[0].map((item) => {
    changenewarr([...newarr, item]) 
    baselineSeries.setData([
       { index: 1, value: parseInt(sparklinedata[0][0][1]), time: sparklinedata[0][0][0] / 1000 },
       { index: 2, value: parseInt(sparklinedata[0][1][1]), time: sparklinedata[0][1][0] / 1000 },
       { index: 3, value: parseInt(sparklinedata[0][2][1]), time: sparklinedata[0][2][0] / 1000 }
    ]);
    })
    useEffect(() => {
      console.log(newarr)
    }, [])

    chart.timeScale().fitContent();

    return () => chart.remove();
  }, []);

  return <div ref={chartContainerRef} />;
}
export default BaselineChart
